118	    prog_clear();
119	    fn_reset();
120	    call_depth = 0;
121	    branch_target = -1;
122	
123	    // Detect batch mode: check if image pointer is set
124	    // APL_IMAGE_PTR holds a 24-bit address; read as int (24-bit on COR24)
125	    int img_addr = *(int *)APL_IMAGE_PTR;
126	    if (img_addr) {
127	        batch_mode = 1;
128	        batch_ptr = (char *)img_addr;
129	    } else {
130	        batch_mode = 0;
131	        batch_ptr = 0;
132	    }
133	
134	    puts("COR24 APL v0.1");
135	
136	    int pc = -1;  // -1 = read from input, >=0 = replay stored line
137	
138	    while (1) {
139	        char *cur_line;
140	        int cur_lineno;  // 1-based line number
141	
142	        if (pc >= 0) {
143	            // Replaying stored line
144	            cur_line = prog_get(pc);
145	            cur_lineno = pc + 1;
146	        } else {
147	            // Read new line from input
148	            int n;
149	            if (batch_mode) {
150	                n = batch_getline(line, IO_LINE_MAX);
151	                if (n < 0) {
152	                    // End of image -- switch to interactive mode
153	                    batch_mode = 0;
154	                    continue;
155	                }
156	            } else {
157	                io_print("      ");
158	                n = io_getline(line, IO_LINE_MAX);
159	            }
160	            if (n == 0) continue;
161	
162	            // Function definition mode: collect body lines
163	            if (fn_def_mode) {
164	                int ci = 0;
165	                while (line[ci] == 32) ci++;
166	                if (str_match(line, ci, "del") == 3 && !is_alnum(line[ci + 3])) {
167	                    // Closing del
168	                    fn_def_mode = 0;
169	                } else if (fn_def_line >= FN_BODY_MAX) {
170	                    io_print("  FN FULL");
171	                    putchar(10);
172	                    fn_def_mode = 0;
173	                } else {
174	                    fn_store_line(fn_def_idx, fn_def_line, line);
175	                    fn_lines[fn_def_idx] = fn_def_line + 1;
176	                    fn_def_line++;
177	                }
178	                continue;
179	            }
180	
181	            // Check for [N] line entry syntax
182	            char *rest;
183	            int lnum = prog_parse_entry(line, &rest);
184	            if (lnum > 0 && lnum <= PROG_MAX) {
185	                prog_store(rest, lnum - 1);
186	                if (lnum > prog_count) prog_count = lnum;
187	                continue;
188	            }
189	
190	            cur_line = line;
191	            cur_lineno = 0;  // immediate mode, no line number
192	        }
193	
194	        // Check for label prefix: IDENT: at start of line
195	        char *exec_line = cur_line;
196	        if (is_upper(cur_line[0])) {
197	            int j = 1;
198	            while (is_alnum(cur_line[j])) j++;
199	            if (cur_line[j] == 58) {  // ':'
200	                // Record label as variable set to line number
201	                int sym_idx = sym_lookup(cur_line, 0);
202	                if (sym_idx >= 0) {
203	                    sym_val[sym_idx] = arr_scalar(cur_lineno);
204	                    sym_set_flag[sym_idx] = 1;
205	                }
206	                j++;
207	                while (cur_line[j] == 32) j++;
208	                exec_line = cur_line + j;
209	                if (exec_line[0] == 0) {
210	                    // Label-only line, no code to execute
211	                    if (pc >= 0) { pc++; if (pc >= prog_count) pc = -1; }
212	                    continue;
213	                }
214	            }
215	        }
216	
217	        if (exec_line[0] == 0) {
218	            // Empty line
219	            if (pc >= 0) { pc++; if (pc >= prog_count) pc = -1; }
220	            continue;
221	        } else if (exec_line[0] == 41) {
222	            // System command: starts with ')'
223	            if (str_match(exec_line, 1, "CLEAR") == 5 && (exec_line[6] == 0 || exec_line[6] == 32)) {
224	                arr_reset();
225	                sym_reset();
226	                fn_reset();
227	                io_print("  CLEAR WS");
228	                putchar(10);
229	            } else if (str_match(exec_line, 1, "VARS") == 4 && (exec_line[5] == 0 || exec_line[5] == 32)) {
230	                int i = 0;
231	                int any = 0;
232	                while (i < sym_count) {
233	                    if (sym_set_flag[i]) {
234	                        if (any) io_print("  ");
235	                        int off = sym_name_off[i];
236	                        while (sym_name_buf[off]) {
237	                            putchar(sym_name_buf[off]);
238	                            off++;
239	                        }
240	                        any = 1;
241	                    }
242	                    i++;
243	                }
244	                if (any) putchar(10);
245	            } else if (str_match(exec_line, 1, "LIST") == 4 && (exec_line[5] == 0 || exec_line[5] == 32)) {
246	                int i = 0;
247	                while (i < prog_count) {
248	                    char *ln = prog_get(i);
249	                    if (ln[0]) {
250	                        putchar(91);  // '['
251	                        print_int(i + 1);
252	                        putchar(93);  // ']'
253	                        putchar(32);
254	                        io_print(ln);
255	                        putchar(10);
256	                    }
257	                    i++;
258	                }
259	            } else if (str_match(exec_line, 1, "RUN") == 3 && (exec_line[4] == 0 || exec_line[4] == 32)) {
260	                if (prog_count > 0) {
261	                    prog_scan_labels();
262	                    pc = 0;
263	                    branch_target = -1;
264	                    continue;
265	                }
266	            } else if (str_match(exec_line, 1, "ERASE") == 5 && (exec_line[6] == 0 || exec_line[6] == 32)) {
267	                prog_clear();
268	            } else if (str_match(exec_line, 1, "FNS") == 3 && (exec_line[4] == 0 || exec_line[4] == 32)) {
269	                int i = 0;
270	                int any = 0;
271	                while (i < fn_count) {
272	                    int sym = fn_name_sym[i];
273	                    if (any) io_print("  ");
274	                    int off = sym_name_off[sym];
275	                    while (sym_name_buf[off]) {
276	                        putchar(sym_name_buf[off]);
277	                        off++;
278	                    }
279	                    any = 1;
280	                    i++;
281	                }
282	                if (any) putchar(10);
283	            } else if (str_match(exec_line, 1, "OFF") == 3 && (exec_line[4] == 0 || exec_line[4] == 32)) {
284	                return 0;
285	            } else {
286	                io_print("  SYNTAX ERROR");
287	                putchar(10);
288	            }
289	        } else {
290	            // Check for "del" function definition (before tokenize, since
291	            // the tokenizer rejects unknown lowercase words)
292	            int di = 0;
293	            while (exec_line[di] == 32) di++;
294	            if (str_match(exec_line, di, "del") == 3 &&
295	                (exec_line[di + 3] == 0 || exec_line[di + 3] == 32)) {
296	                int after = di + 3;
297	                while (exec_line[after] == 32) after++;
298	                if (exec_line[after] == 0) {
299	                    // Bare "del" outside definition mode
300	                    io_print("  SYNTAX ERROR");
301	                    if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
302	                    putchar(10);
303	                } else if (pc >= 0) {
304	                    // Can't define functions during program execution
305	                    io_print("  SYNTAX ERROR");
306	                    io_print(" ["); print_int(pc + 1); putchar(93); pc = -1;
307	                    putchar(10);
308	                } else {
309	                    // Start function definition
310	                    int temp = fn_count;
311	                    if (temp >= FN_MAX) {
312	                        io_print("  FN TABLE FULL");
313	                        putchar(10);
314	                    } else if (!parse_fn_header(exec_line + after, temp)) {
315	                        io_print("  SYNTAX ERROR");
316	                        putchar(10);
317	                    } else {
318	                        // Check for existing function with same name
319	                        int ns = fn_name_sym[temp];
320	                        int exi = 0;
321	                        int found = -1;
322	                        while (exi < fn_count) {
323	                            if (fn_name_sym[exi] == ns) found = exi;
324	                            exi++;
325	                        }
326	                        if (found >= 0) {
327	                            // Redefine existing function
328	                            fn_result_sym[found] = fn_result_sym[temp];
329	                            fn_right_sym[found] = fn_right_sym[temp];
330	                            fn_left_sym[found] = fn_left_sym[temp];
331	                            fn_lines[found] = 0;
332	                            fn_def_idx = found;
333	                        } else {
334	                            fn_count++;
335	                            fn_def_idx = temp;
336	                        }
337	                        fn_def_mode = 1;
338	                        fn_def_line = 0;
339	                    }
340	                }
341	                if (pc >= 0) { pc++; if (pc >= prog_count) pc = -1; }
342	                continue;
343	            }
344	
345	            int ntok = tokenize(exec_line);
346	            if (ntok < 0) {
347	                io_print("  SYNTAX ERROR");
348	                if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
349	                putchar(10);
350	            } else {
351	                // Save heap position for temporary reclamation
352	                int heap_save = heap_top;
353	
354	                int root = parse(exec_line);
355	                if (root < 0) {
356	                    heap_top = heap_save;
357	                    io_print("  SYNTAX ERROR");
358	                    if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
359	                    putchar(10);
360	                } else {
361	                    eval_err = 0;
362	                    branch_target = -1;
363	                    int result = eval(root);
364	                    if (eval_err == 2) {
365	                        heap_top = heap_save;
366	                        io_print("  VALUE ERROR");
367	                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
368	                        putchar(10);
369	                    } else if (eval_err == 3) {
370	                        heap_top = heap_save;
371	                        io_print("  LENGTH ERROR");
372	                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
373	                        putchar(10);
374	                    } else if (eval_err == 4) {
375	                        heap_top = heap_save;
376	                        io_print("  RANK ERROR");
377	                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
378	                        putchar(10);
379	                    } else if (eval_err == 5) {
380	                        heap_top = heap_save;
381	                        io_print("  WS FULL");
382	                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
383	                        putchar(10);
384	                    } else if (eval_err) {
385	                        heap_top = heap_save;
386	                        io_print("  DOMAIN ERROR");
387	                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
388	                        putchar(10);
389	                    } else if (node_type[root] == NODE_ASSIGN) {
390	                        // Assignment: no output (APL convention)
391	                        // Don't restore heap -- variable value persists
392	                    } else if (node_type[root] == NODE_QLED_ASSIGN) {
393	                        // Quad LED assignment: no output
394	                        heap_top = heap_save;
395	                    } else if (node_type[root] == NODE_SVO_WRITE) {
396	                        // Shared variable indexed write: no output
397	                        heap_top = heap_save;
398	                    } else if (node_type[root] == NODE_GOTO || node_type[root] == NODE_CGOTO) {
399	                        // Branch: no output
400	                        heap_top = heap_save;
401	                    } else {
402	                        // Print result based on rank
403	                        int rank = arr_rank(result);
404	                        if (rank == 0) {
405	                            io_print("  ");
406	                            print_int(arr_get(result, 0));
407	                            putchar(10);
408	                        } else if (rank == 1) {
409	                            int sz = arr_dim0(result);
410	                            // Find max width across all elements
411	                            int maxw = 1;
412	                            int j = 0;
413	                            while (j < sz) {
414	                                int w = num_width(arr_get(result, j));
415	                                if (w > maxw) maxw = w;
416	                                j++;
417	                            }
418	                            // Print each element right-justified
419	                            j = 0;
420	                            while (j < sz) {
421	                                if (j == 0) putchar(32);
422	                                print_int_rj(arr_get(result, j), maxw);
423	                                if (j + 1 < sz) putchar(32);
424	                                j++;
425	                            }
426	                            putchar(10);
427	                        } else if (rank == 2) {
428	                            int rows = arr_dim0(result);
429	                            int cols = arr_dim1(result);
430	                            int sz = rows * cols;
431	                            // Find max width across all elements
432	                            int maxw = 1;
433	                            int j = 0;
434	                            while (j < sz) {
435	                                int w = num_width(arr_get(result, j));
436	                                if (w > maxw) maxw = w;
437	                                j++;
438	                            }
439	                            // Print each row on its own line
440	                            int r = 0;
441	                            while (r < rows) {
442	                                int c = 0;
443	                                while (c < cols) {
444	                                    if (c == 0) putchar(32);
445	                                    print_int_rj(arr_get(result, r * cols + c), maxw);
446	                                    if (c + 1 < cols) putchar(32);
447	                                    c++;
448	                                }
449	                                putchar(10);
450	                                r++;
451	                            }
452	                        }
453	                        // Reclaim temporaries
454	                        heap_top = heap_save;
455	                    }
456	                }
457	            }
458	        }
459	
460	        // Check for branch
461	        if (branch_target > 0) {
462	            pc = branch_target - 1;  // convert 1-based to 0-based
463	            branch_target = -1;
464	            continue;
465	        } else if (branch_target == 0) {
466	            // goto 0: stop execution
467	            if (pc >= 0) {
468	                // In program mode: return to immediate mode
469	                pc = -1;
470	                branch_target = -1;
471	                continue;
472	            }
473	            // In immediate mode: exit interpreter
474	            return 0;
475	        }
476	
477	        // Advance PC if replaying stored lines
478	        if (pc >= 0) {
479	            pc++;
480	            if (pc >= prog_count) pc = -1;
481	        }
482	    }
483	    return 0;
484	}
