// COR24 APL Interpreter -- I/O layer
// Wraps UART for line-oriented input with editing support.

#pragma once

#include <stdio.h>

#define IO_LINE_MAX 120

// Read a line from UART into buf (max len-1 chars + NUL).
// Handles backspace (BS=8, DEL=127): erases last char, sends BS-SPACE-BS.
// Returns number of chars read (excluding NUL), or 0 on empty line.
// Echoes characters as typed. Terminates on CR (13) or LF (10).
int io_getline(char *buf, int len) {
    int pos = 0;
    int maxpos = len - 1;

    while (1) {
        int ch = getchar();

        if (ch == 10 || ch == 13) {
            // Newline -- terminate
            putchar(10);
            buf[pos] = 0;
            return pos;
        }

        if (ch == 8 || ch == 127) {
            // Backspace or DEL -- erase last char
            if (pos > 0) {
                pos--;
                putchar(8);   // BS
                putchar(32);  // space
                putchar(8);   // BS
            }
        } else if (ch >= 32 && pos < maxpos) {
            // Printable character
            buf[pos] = ch;
            pos++;
            putchar(ch);
        }
        // Ignore other control chars and overflow
    }
}

// Print a string without trailing newline
void io_print(char *s) {
    while (*s) {
        putchar(*s);
        s = s + 1;
    }
}

## UART I/O

### Input

```c
int uart_getchar(void) {
    volatile int *status = (int *)0xFF0101;
    volatile int *data   = (int *)0xFF0100;
    while (!(*status & 1))  /* wait for RX ready */
        ;
    return *data & 0xFF;
}
```

Line buffer: 256 bytes. Read until newline. Support backspace
(delete last char, echo BS-SPACE-BS).

### Output

```c
void uart_putchar(int ch) {
    volatile int *status = (int *)0xFF0101;
    volatile int *data   = (int *)0xFF0100;
    while (*status & 0x80)  /* wait for TX not busy */
        ;
    *data = ch;
}
```

### Number Printing

Right-justify integers in a field width. For matrices, pre-scan
each column to determine maximum width, then format accordingly.

## Testing Approach

### Test Harness

Use cor24-run with UART I/O capture. Feed input expressions via
stdin, capture UART output, compare to expected.

### Test Cases (representative)

```
Input:                    Expected output:
3 + 4                     7
iota 5                    0 1 2 3 4
2 3 rho iota 6           0 1 2
                          3 4 5
+/ iota 10               45

